sql:
SELECT COUNT(*) AS number_of_establishments
FROM establishments
WHERE state = 'California';

external_knowledge:
- 'beacons of comfort' metaphorically refers to lodging establishments;
- 'weathered the storms of traveler's critiques' implies enduring the evaluation by travelers through ratings;
- 'how serene have their havens been rated on average' refers to the average rating of these lodgings;
- 'along the shores' indicates the coastal locations of these establishments.

sql:
SELECT AVG(r.rating_value) AS average_rating
FROM ratings r
JOIN reviews v ON r.establishment_id = v.establishment_id AND r.user_id = v.user_id;
